class Solution {
public:
    int latestTimeCatchTheBus(vector<int>& buses, vector<int>& passengers, int capacity) {
        sort(buses.begin(), buses.end());
        sort(passengers.begin(), passengers.end());
        int i = 0, cnt = 0, res = -1;
        for (int bus : buses) {
            cnt = 0;
            while (i < passengers.size() && passengers[i] <= bus && cnt < capacity) {
                if (passengers[i] < bus) res = passengers[i];
                i++, cnt++;
            }
            if (cnt < capacity) res = bus;
        }
        return res;
    }
};
